<?php
$k = $_GET['k'] ?? '';
if ($k !== 'sl_deploy_2026') { http_response_code(403); die('Forbidden'); }

// Deploy into uploads/ — writable by www-data
$base = __DIR__ . '/';   // deploy3.php is in uploads/, so this is uploads/
$files = [    'api/auth/login.php' => '',
    'api/auth/logout.php' => '',
    'api/auth/me.php' => '',
    'api/auth/register.php' => '',
    'api/config/db.php' => '',
    'api/config/helpers.php' => '',
    'api/events/create.php' => '',
    'api/events/list.php' => '',
    'api/events/signup.php' => '',
    'api/messages/conversations.php' => '',
    'api/messages/list.php' => '',
    'api/messages/send.php' => '',
    'api/notifications/list.php' => '',
    'api/notifications/mark_read.php' => '',
    'api/requests/create.php' => '',
    'api/requests/list.php' => '',
    'api/requests/update.php' => '',
    'api/users/delete.php' => '',
    'api/users/list.php' => '',
    'api/users/rate.php' => '',
    'api/users/update.php' => '',
    'api/users/upload_photo.php' => '',
    'setup.php' => '',
    'reset_password.php' => '',
    'api/auth/forgot_password.php' => '',
    'api/availability/set.php' => '',
    'api/timetable/upload.php' => '',
];

$ok = []; $err = [];
foreach ($files as $path => $encoded) {
    $full = $base . $path;
    $dir  = dirname($full);
    if (!is_dir($dir)) {
        if (!mkdir($dir, 0755, true)) {
            $err[] = "mkdir failed: $dir"; continue;
        }
    }
    $bytes = base64_decode($encoded, true);
    if ($bytes === false) { $err[] = "base64_decode failed: $path"; continue; }
    if (file_put_contents($full, $bytes) === false) {
        $err[] = "write failed: $path";
    } else {
        $ok[] = $path;
    }
}

header('Content-Type: text/plain');
echo "=== SignLink Deploy ===\n\n";
echo "Base: $base\n\n";
echo "OK (" . count($ok) . "):\n";
foreach ($ok  as $p) echo "  + $p\n";
echo "\nFAILED (" . count($err) . "):\n";
foreach ($err as $e) echo "  ! $e\n";
echo "\nDone.\n";